var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"힐데 소대장님, 어떻게 된 거죠?","JPN":"ヒルデ小隊長、どうなっているんですか？","ENG":"Commander Hilde, what’s going on?","TWN":"希爾德小隊長，這是怎麼回事？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_EARTHQUAKE"},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"오비탈 베이스가 강제로 끌려가고 있다.","JPN":"オービタルベースが強制的に引っ張られている。","ENG":"The Orbital Base is being dragged to another location.","TWN":"軌道基地正強行被拖走，"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"도착지는 아마도 그림자 전당으로 추정된다더군.","JPN":"到着地はおそらく影の殿堂とみられるそうだ。","ENG":"The destination is predicted to be the Shadow Palaces.","TWN":"推測目的地是暗影殿堂。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그림자 전당? 한탕만 쫓는 멍청이들의 무덤이라는 그 고위험 좌표요?","JPN":"影の殿堂？　一発逆転ばかりを狙うおばかさんたちの墓っていう、あの高危険度の座標ですか？","ENG":"The Shadow Palaces? You mean the highly dangerous coordinates known as Fools’ Folly?","TWN":"暗影殿堂？是有窮追不捨傻瓜墳場之稱的高危險座標嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"알고 있나?","JPN":"知っているのか？","ENG":"Do you know about it?","TWN":"你知道那個地方？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"모를 리가 없죠. 관리국에서 공식적으로 발표한 좌표인데요.","JPN":"知らないわけがないでしょう。管理局で公式的に発表した座標ですし。","ENG":"How could I not? Those are coordinates officially published by the Administration.","TWN":"怎麼可能不知道，那不是管理局正式公佈的座標嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 그림자들과는 처음 입사했을 때부터 안 좋은 인연이기도 했고요.","JPN":"それに、シャドウとは初めて入社したときからの腐れ縁でもあります。","ENG":"Also, I had a few bad run-ins with Shadows ever since I first joined.","TWN":"而且從我剛進公司時，就和暗影有過不好的經驗。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 더 설명할 필요 없겠군. 이수연 부사장이 우릴 뒤따라올 때까지 오비탈 베이스를 사수한다.","JPN":"では説明する必要もないな。カナミ副社長が我々に追いつくまでオービタルベースを死守する。","ENG":"Then I won’t have to provide further explanation. We must secure the Orbital Base until Vice President Lee Sooyeon arrives.","TWN":"那無須再多做解釋，在李秀妍副總抵達前，務必守住軌道基地。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"힐데 소대장님이 계시니까 정면은 물론 걱정이 없겠지만……","JPN":"ヒルデ小隊長がいらっしゃるから正面は心配ないとしても……","ENG":"Since you’re here, I’m not too worried about the front...","TWN":"前面有希爾德小隊長在應該是不需要擔心……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여긴 그림자들이 우글거리는 곳이라고 들었어요.","JPN":"ここはシャドウがうようよいる場所だそうです。","ENG":"However, I heard that this place is crawling with Shadows.","TWN":"但我聽說這裡是暗影聚集的地方，"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"저희들만으로 오비탈 베이스를 방어하기는 어려울 걸요.","JPN":"私たちだけでオービタルベースを守るのは難しいと思いますよ。","ENG":"It may be difficult to defend the Orbital Base by ourselves.","TWN":"光憑我們幾個恐怕很難守住軌道基地。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그건 곤란하군.","JPN":"……それは困るな。","ENG":"...That’s bad news.","TWN":"……傷腦筋呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전투가 길어지면 도플갱어 신드롬도 악화될 가능성이 커.","JPN":"戦闘が長引けばドッペルゲンガーシンドロームも悪化する可能性が高い。","ENG":"The longer the battle drags on, the higher the risk of Doppelganger Syndrome getting worse.","TWN":"作戰時間拉得越長，二重身症候群增加的可能性也越大。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 도플갱어 신드롬 말인데, 그림자와는 다른 건가요?","JPN":"そのドッペルゲンガーシンドロームですが、シャドウとは違うんですか？","ENG":"This Doppelganger Syndrome you just mentioned, is it different from the Shadows?","TWN":"那個所謂的二重身症候群，和暗影是不同的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 이 공간의 침식파가 내부에서 활동하는 개체의 에너지에 반응해 대상의 복제를 만들어 내는 거다.","JPN":"そうだ。この空間の侵食波が内部で活動する個体のエネルギーに反応して、対象のクローンを作り出すんだ。","ENG":"That’s correct. The Corruption Ray permeating throughout this space will respond to an active entity’s energy and create a clone.","TWN":"嗯，這個空間的侵蝕波會對在裡面的個體能量產生反應，再製造出該個體的複製品。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"카운터가 변이하는 그림자와 비교하면 일종의 대량 생산품인 셈이지.","JPN":"カウンターが変異するシャドウと比べると、一種の大量生産品というわけだ。","ENG":"If you compare it to a Shadow, which is a morphed Counter, it’s the equivalent of a mass produced item.","TWN":"暗影是變種的制裁者，二重身則是一種可以大量生產的複製品。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전투로 방출되는 에너지가 늘어나거나, 혹은 다른 이유로나 악화되면 끝도 없이 쏟아져 나오게 되지.","JPN":"戦闘で放出されるエネルギーが増大するか、他の理由ででも、悪化すれば際限なく溢れ出るようになる。","ENG":"If the energy released during a battle is increased, or gets corrupted for some other reason, they’ll keep pouring in an endless tide.","TWN":"當能量因為戰鬥或是其他理由而增加時，複製品就會不斷地湧現。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……설명만 들어도 끔찍하네요.","JPN":"……説明だけ聞いてもぞっとしますね。","ENG":"...Just hearing about it gives me the chills.","TWN":"……光聽就覺得可怕。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그러니 접근하는 도플갱어들을 되도록 신속하게 격퇴해야 한다.","JPN":"だから接近してくるドッペルゲンガーをできるだけ迅速に撃退しなければならない。","ENG":"Therefore, all approaching Doppelgangers must be destroyed quickly.","TWN":"因此一定要盡可能迅速消滅靠近的二重身。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 그림자 전당이 너에 대해 관심을 가지기 전에 말이야.","JPN":"この影の殿堂がお前に関心を向ける前にな。","ENG":"Before the Shadow Palaces take an interest in you.","TWN":"而且必須搶在暗影殿堂盯上你之前。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"으음, 하지만 지금 전력으로는……","JPN":"うーん、ですが現在の戦力では……","ENG":"Hmm... But with the forces that we currently have...","TWN":"嗯嗯，可是以現在的戰力……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_QM","text":{"KOREA":"<color=#ffd34c>여어, 기병대가 도착했다.</color>","JPN":"<color=#ffd34c>よう、騎兵隊が到着したぞ。</color>","ENG":"<color=#ffd34c>The cavalry has arrived!</color>","TWN":"<color=#ffd34c>唷呵，救兵來囉！</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_QM","text":{"KOREA":"<color=#ffd34c>혹시 도움이 필요한가 아가씨?</color>","JPN":"<color=#ffd34c>ひょっとして助けが必要か、お嬢さん？</color>","ENG":"<color=#ffd34c>Do you need any help, ladies?</color>","TWN":"<color=#ffd34c>小姐需要幫忙嗎？</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"통신? 어디서 들어오는 거지?","JPN":"通信？　どこから入ってくるの？","ENG":"Huh? Where are the comms coming from?","TWN":"通訊？是怎麼打進來的？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"군용 통신에 대고 헛소리 하지 마! 이 멍청아!","JPN":"軍用通信でたわ言を発信しないでよ！　このバカ！","ENG":"Don’t fool around on a military channel, stupid head!","TWN":"不要亂玩軍用通訊啦！你這笨蛋！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"크흠. 아, 미안. 거기 오비탈 베이스에 타고 있는 거 코핀 컴퍼니 친구들 맞지?","JPN":"コホン。あ、ごめん。そっちのオービタルベースに乗ってるのはコフィンカンパニーの社員だよね？","ENG":"Ahem, sorry about that. You guys on the Orbital Base, you’re from Coffin Company, right?","TWN":"咳咳，不好意思，現在在搭乘軌道基地的是科芬公司的人吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 네. 알트 소대장 서윤입니다.","JPN":"あっ、はい。アルト小隊長のアオイです。","ENG":"Yes. This is ALT Squad Commander, Seo Yoon.","TWN":"嗯，對，我是阿爾特小隊長 徐芸。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 목소리는…… 델타 세븐 분인가요?","JPN":"その声は……デルタセブンの方ですか？","ENG":"That voice... Are you Delta Seven?","TWN":"聽這聲音……是第七三角洲部隊的人嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"맞아. 지난번엔 신세를 많이 졌지. 이자를 좀 갚으러 왔어.","JPN":"そうよ。この前はお世話になったわね。借りを返そうと思って来たの。","ENG":"That’s right. I owe you one for last time, so I’m here to repay that with interest.","TWN":"沒錯，上次多虧有你們的幫忙，我們是來還人情的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오비탈 베이스의 내부 통신망을 잠깐 해킹했는데 곤란한 상황이라며?","JPN":"オービタルベース内部の通信網をちょこっとハッキングしたんだけど、困ってるらしいじゃない？","ENG":"I briefly hacked the Orbital Base’s internal network earlier. From what I heard, you guys are in a bit of a tight spot?","TWN":"我駭進軌道基地內部的通訊網，聽到你們遇到些困難是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……해킹이라니 무서운 말을 아주 편안하게 하시네요.","JPN":"……ハッキングだなんて、恐しいことを平気で言うんですね。","ENG":"\\"Hacked the network...\\" You say some pretty scary stuff as if it’s nothing.","TWN":"……駭進人家通訊網這麼可怕的事，你的語氣還真是稀鬆平常呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아무튼 맞아요. 여기 그림자 전당의 특성상 장기전이 될수록 도플갱어들이 늘어날 가능성도 커진다고 하네요.","JPN":"それはいいとして、そうなんです。ここ影の殿堂の特性上、長期戦になるほどドッペルゲンガーが増える可能性が高くなるらしくて。","ENG":"Anyway, you’re right. Due to how the Shadow Palaces work, the longer the battle, the more Doppelgangers come.","TWN":"總之你說的沒錯，聽說暗影殿堂的特徵就是，作戰時間越長，二重身增加的數量就越多。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러면 번개처럼 처리할 필요가 있겠군.","JPN":"だったら電光石火で処理しないとな。","ENG":"Then we’re gonna have to take them out as quick as lightning.","TWN":"那就需要像閃電一樣速戰速決囉！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"들었지? 우리 쪽 인원이 전투에 참가할 거야.","JPN":"聞いたでしょ？　アタシたちも戦闘に参加するわ。","ENG":"You hear that? Our forces will be joining the battle.","TWN":"聽到沒？我們的人也要加入作戰。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 마구 부려먹으라고. 시간에 늦지 않게.","JPN":"だから存分にこき使って。手遅れにならないうちに。","ENG":"Therefore, you should take this opportunity and use them well. So that it's not too late.","TWN":"趕快召集大家，動作快！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"무슨 일이죠? 또다른 손님이 오신 건가요?","JPN":"どうしたんですか？　また他のお客様がいらしたんですか？","ENG":"What’s going on? Are more guests arriving?","TWN":"怎麼回事？又有其他客人來訪嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네. 아무래도 지원군이 온 것 같아요.","JPN":"はい。どうやら応援が来たようです。","ENG":"Yes, it seems that reinforcements have arrived.","TWN":"對，看來是援軍駕到。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이렇게 되면 승산이 있네요. 타이밍이 늦지 않게 빨리 합류해야겠어요.","JPN":"こうなると勝算がありますね。タイミングを逃さずに早く合流しなければ。","ENG":"Now we have a chance of winning. We shouldn’t miss our chance. Let’s join them quickly.","TWN":"這樣的話應該有勝算，必須盡快會合。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"좋아, 세부적인 조정은 서윤 소대장에게 맡기지.","JPN":"よし、細かい部分の調整はアオイ小隊長に任せる。","ENG":"Okay, I’ll leave the detailed adjustments to you, Commander Seo Yoon.","TWN":"好，細微的調整就交給徐芸小隊長負責！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"전 대원, 출격한다!","JPN":"全隊員、出撃！","ENG":"All hands, deploy!","TWN":"全員出擊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};